// src/Dashboard.js
import React, { useEffect, useState } from "react";

const apiBase = "https://prasa-backend-1.onrender.com";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";
const white = "#ffffff";

function Dashboard({ employee, onLogout }) {
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [travelForm, setTravelForm] = useState({
    travel_date: "",
    purpose: "",
    amount: "",
    location_from: "",
    location_to: "",
    mode_of_travel: "",
  });
  const [ticketForm, setTicketForm] = useState({
    ticket_date: "",
    purpose: "",
    assigned_to: "",
    amount: "",
  });
  const [message, setMessage] = useState("");
  const [view, setView] = useState("dashboard");

  useEffect(() => {
    if (employee && employee.empld) {
      fetchData();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [employee]);

  const fetchData = async () => {
    try {
      setMessage("Loading...");
      const [tRes, kRes] = await Promise.all([
        fetch(`${apiBase}/travel-expenses?empld=${encodeURIComponent(employee.empld)}`),
        fetch(`${apiBase}/ticket-expenses?empld=${encodeURIComponent(employee.empld)}`),
      ]);

      if (!tRes.ok || !kRes.ok) throw new Error("Server not responding.");

      const [travel, tickets] = await Promise.all([tRes.json(), kRes.json()]);

      setTravelExpenses(travel || []);
      setTicketExpenses(tickets || []);
      setMessage("");
    } catch (error) {
      console.error("Fetch Error:", error);
      setMessage("❌ Could not load data. Check your server.");
    }
  };

  const submitTravel = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const res = await fetch(`${apiBase}/travel-expenses`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          empld: employee.empld,
          ...travelForm,
          amount: parseFloat(travelForm.amount || 0),
        }),
      });
      const data = await res.json();
      if (data.success) {
        setMessage("✅ Travel expense added!");
        setTravelForm({
          travel_date: "",
          purpose: "",
          amount: "",
          location_from: "",
          location_to: "",
          mode_of_travel: "",
        });
        fetchData();
      } else {
        setMessage("❌ " + (data.message || "Failed"));
      }
    } catch (err) {
      console.error(err);
      setMessage("❌ Server error while adding travel expense.");
    }
  };

  const submitTicket = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const res = await fetch(`${apiBase}/ticket-expenses`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          empld: employee.empld,
          ...ticketForm,
          amount: parseFloat(ticketForm.amount || 0),
        }),
      });
      const data = await res.json();
      if (data.success) {
        setMessage("✅ Ticket expense added!");
        setTicketForm({
          ticket_date: "",
          purpose: "",
          assigned_to: "",
          amount: "",
        });
        fetchData();
      } else {
        setMessage("❌ " + (data.message || "Failed"));
      }
    } catch (err) {
      console.error(err);
      setMessage("❌ Server error while adding ticket.");
    }
  };

  return (
    <div style={{ fontFamily: "Segoe UI", background: lightGreen, minHeight: "100vh", padding: 24 }}>
      <div style={{ maxWidth: 1100, margin: "0 auto", background: white, borderRadius: 12, boxShadow: "0 6px 20px rgba(0,0,0,0.08)", overflow: "hidden" }}>
        <header style={{ padding: 20, background: green, color: white, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <h1 style={{ margin: 0 }}>PRASA Employee Dashboard</h1>
            <div style={{ marginTop: 8 }}>{employee.name} — {employee.department} | {employee.role || "Employee"}</div>
          </div>

          <button onClick={onLogout} style={{ background: "white", color: green, padding: "8px 14px", borderRadius: 6, border: "none", cursor: "pointer", fontWeight: "bold" }}>
            Logout
          </button>
        </header>

        <main style={{ padding: 20 }}>
          <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
            <button onClick={() => setView("dashboard")} style={buttonPrimary()}>🧑‍💼 Dashboard</button>
            <button onClick={() => setView("form")} style={buttonOutline()}>➕ Add New</button>
            <button onClick={() => setView("history")} style={buttonOutline()}>📜 History</button>
          </div>

          {view === "dashboard" && (
            <div>
              <h2 style={{ color: green }}>Employee Information</h2>
              <div style={{ border: `1px solid ${lightGreen}`, background: "#f9fff9", padding: 20, borderRadius: 10, marginBottom: 30 }}>
                <p><strong>Name:</strong> {employee.name}</p>
                <p><strong>Emp ID:</strong> {employee.empld}</p>
                <p><strong>Department:</strong> {employee.department}</p>
                <p><strong>Role:</strong> {employee.role}</p>
                <p><strong>Email:</strong> {employee.email}</p>
                <p><strong>Phone:</strong> {employee.phone}</p>
                <p><strong>Joining Date:</strong> {employee.joiningDate}</p>
              </div>

              <h3 style={{ color: green }}>Quick Summary</h3>
              <p>🚌 Travel Expenses: {travelExpenses.length}</p>
              <p>🎫 Ticket Expenses: {ticketExpenses.length}</p>
            </div>
          )}

          {view === "form" && (
            <div style={{ display: "flex", gap: 20 }}>
              <div style={{ flex: 1 }}>
                <h3 style={{ color: green }}>Add Travel Expense</h3>
                <form onSubmit={submitTravel} style={formStyle()}>
                  <input type="date" required value={travelForm.travel_date} onChange={(e) => setTravelForm({ ...travelForm, travel_date: e.target.value })} style={inputStyle()} />
                  <input placeholder="Purpose" required value={travelForm.purpose} onChange={(e) => setTravelForm({ ...travelForm, purpose: e.target.value })} style={inputStyle()} />
                  <input placeholder="Amount" type="number" required value={travelForm.amount} onChange={(e) => setTravelForm({ ...travelForm, amount: e.target.value })} style={inputStyle()} />
                  <input placeholder="From" value={travelForm.location_from} onChange={(e) => setTravelForm({ ...travelForm, location_from: e.target.value })} style={inputStyle()} />
                  <input placeholder="To" value={travelForm.location_to} onChange={(e) => setTravelForm({ ...travelForm, location_to: e.target.value })} style={inputStyle()} />
                  <button type="submit" style={buttonPrimary()}>Submit</button>
                </form>

                <h3 style={{ color: green, marginTop: 20 }}>Add Ticket Expense</h3>
                <form onSubmit={submitTicket} style={formStyle()}>
                  <input type="date" required value={ticketForm.ticket_date} onChange={(e) => setTicketForm({ ...ticketForm, ticket_date: e.target.value })} style={inputStyle()} />
                  <input placeholder="Purpose" required value={ticketForm.purpose} onChange={(e) => setTicketForm({ ...ticketForm, purpose: e.target.value })} style={inputStyle()} />
                  <input placeholder="Assigned To" value={ticketForm.assigned_to} onChange={(e) => setTicketForm({ ...ticketForm, assigned_to: e.target.value })} style={inputStyle()} />
                  <input placeholder="Amount" type="number" required value={ticketForm.amount} onChange={(e) => setTicketForm({ ...ticketForm, amount: e.target.value })} style={inputStyle()} />
                  <button type="submit" style={buttonPrimary()}>Submit</button>
                </form>
              </div>
            </div>
          )}

          {view === "history" && (
            <div>
              <h3 style={{ color: green }}>Travel Expense History</h3>
              <table style={tableStyle()}>
                <thead>
                  <tr>
                    <th>Date</th><th>Purpose</th><th>Amount</th><th>From</th><th>To</th>
                  </tr>
                </thead>
                <tbody>
                  {travelExpenses.map((t) => (
                    <tr key={t.id}>
                      <td>{t.travel_date?.split?.("T")?.[0] || t.travel_date}</td>
                      <td>{t.purpose}</td>
                      <td>₹{t.amount}</td>
                      <td>{t.location_from}</td>
                      <td>{t.location_to}</td>
                    </tr>
                  ))}
                </tbody>
              </table>

              <h3 style={{ color: green, marginTop: 20 }}>Ticket Expense History</h3>
              <table style={tableStyle()}>
                <thead>
                  <tr><th>Date</th><th>Purpose</th><th>Assigned To</th><th>Amount</th></tr>
                </thead>
                <tbody>
                  {ticketExpenses.map((t) => (
                    <tr key={t.id}>
                      <td>{t.ticket_date?.split?.("T")?.[0] || t.ticket_date}</td>
                      <td>{t.purpose}</td>
                      <td>{t.assigned_to}</td>
                      <td>₹{t.amount}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {message && <div style={{ color: green, marginTop: 12 }}>{message}</div>}
        </main>
      </div>
    </div>
  );
}

function inputStyle() {
  return { display: "block", width: "100%", padding: 8, marginBottom: 8, borderRadius: 6, border: "1px solid #ccc" };
}
function buttonPrimary() {
  return { background: "#0f9d58", color: "white", border: "none", padding: "10px 16px", borderRadius: 6, cursor: "pointer" };
}
function buttonOutline() {
  return { background: "white", border: `2px solid ${green}`, padding: "8px 16px", borderRadius: 6, color: green, cursor: "pointer" };
}
function formStyle() {
  return { background: "#fbfff9", padding: 12, borderRadius: 8 };
}
function tableStyle() {
  return { width: "100%", borderCollapse: "collapse", marginTop: 10 };
}

export default Dashboard;
